arguments.file_text:
@if (TotalPages > 1)
{
    <nav aria-label="Product catalog pagination">
        <ul class="pagination justify-content-center mt-4">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage - 1))" disabled="@(CurrentPage <= 1)">Previous</button>
            </li>
            @foreach (var page in GetPageNumbers())
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(page))">@page</button>
                </li>
            }
            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage + 1))" disabled="@(CurrentPage >= TotalPages)">Next</button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, CurrentPage - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

@if (IsLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2 text-muted">Loading products...</p>
    </div>
}
else if (ErrorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @ErrorMessage
    </div>
}
else if (Products is null || Products.Count == 0)
{
    <div class="text-center py-5 text-muted">
        <h4>No products found</h4>
        <p>Try adjusting your filters.</p>
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnProductSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public List<Product>? Products { get; set; }

    [Parameter]
    public bool IsLoading { get; set; }

    [Parameter]
    public string? ErrorMessage { get; set; }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="row">
    <div class="col-md-3">
        <CatalogSidebar Categories="_categories"
                        OnFiltersApplied="HandleFiltersApplied"
                        OnFiltersCleared="HandleFiltersCleared" />
    </div>

    <div class="col-md-9">
        <CatalogToolbar SortBy="@_sortBy"
                        TotalCount="_totalCount"
                        Page="_currentPage"
                        PageSize="@PageSize"
                        OnSortChanged="HandleSortChanged" />

        <ProductGrid Products="_products"
                     IsLoading="_isLoading"
                     ErrorMessage="@_errorMessage"
                     OnProductSelected="HandleProductSelected"
                     OnAddToCart="HandleAddToCart" />

        <CatalogPagination CurrentPage="_currentPage"
                           TotalPages="_totalPages"
                           OnPageChanged="HandlePageChanged" />
    </div>
</div>

@code {
    private const int PageSize = 12;

    private List<Product>? _products;
    private List<string>? _categories;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _isLoading = true;
    private string? _errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await SearchAsync();
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            _categories = new();
        }
    }

    private async Task SearchAsync()
    {
        _isLoading = true;
        _errorMessage = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products. {ex.Message}";
            _products = null;
            _totalCount = 0;
            _totalPages = 0;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFiltersCleared()
    {
        _filter = new(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }
}

